/// <summary>
/// <c>ETGProdTableETGIsSubcontractingOrderOnModified_EventHandler</c> Event Handler class
/// to handle the controls and validations.
/// </summary>
internal final class ETGProdTableETGIsSubcontractingOrderOnModified_EventHandler
{


}

Method.Source:
[FormControlEventHandler(formControlStr(ProdTableCreate, ProdTable_ETGIsSubcontractingOrder),FormControlEventType::Modified)]
public static void ProdTable_ETGIsSubcontractingOrder_OnModified(FormControl sender,FormControlEventArgs e)
{
    FormRun             formRun;
    FormControl         salesIdControl,ETGParentEntityControl,ETGParentWareHouseControl,itemIdControl;
    FormCheckBoxControl isSubcontractingCtrl;
    NoYes               isSubcontracting;

    isSubcontractingCtrl = sender as FormCheckBoxControl;
    formRun              = isSubcontractingCtrl.formRun();

    FormDataSource prodTableDs = formRun.dataSource(formDataSourceStr(ProdTableCreate, ProdTable));
    ProdTable      prodTable   = prodTableDs.cursor();

    salesIdControl            = formRun.design().controlName(formControlStr(ProdTableCreate, ProdTable_ETGSalesId));
    ETGParentEntityControl    = formRun.design().controlName(formControlStr(ProdTableCreate, ProdTable_ETGParentEntity));
    ETGParentWareHouseControl = formRun.design().controlName(formControlStr(ProdTableCreate, ProdTable_ETGParentWareHouse));
    itemIdControl             = formRun.design().controlName(formControlStr(ProdTableCreate, ProdTable_ETGItemId));


    isSubcontracting = isSubcontractingCtrl.value();

    if (isSubcontracting == NoYes::Yes)
    {
        salesIdControl.enabled(true);
        ETGParentEntityControl.enabled(true);
        ETGParentWareHouseControl.enabled(true);
        itemIdControl.enabled(true);
        prodTableDs.object(fieldNum(ProdTable, ETGParentEntity)).mandatory(true);
        prodTableDs.object(fieldNum(ProdTable, ETGParentWareHouse)).mandatory(true);
        ETGLegalEntityListForSUbcontractingProdOrder etgLegalEntityListForSUbcontractingProdOrder;
        select firstonly etgLegalEntityListForSUbcontractingProdOrder;
        prodTable.ETGParentEntity = etgLegalEntityListForSUbcontractingProdOrder.LegalEntityName;
    }

    else
    {
        if (prodTableDs)
        {
            prodTable.ETGSalesId = '';
            prodTable.ETGItemId = '';
            prodTableDs.refresh();
        }

        salesIdControl.enabled(false);
        itemIdControl.enabled(false);
        ETGParentEntityControl.enabled(false);
        ETGParentWareHouseControl.enabled(false);
    }
}

/// <summary>
///
/// </summary>
/// <param name="sender"></param>
/// <param name="e"></param>
[FormControlEventHandler(formControlStr(ProdTableCreate, ProdTable_ETGSalesId), FormControlEventType::Modified)]
public static void ProdTable_ETGSalesId_OnModified(FormControl sender, FormControlEventArgs e)
{
    FormRun formRun = sender.formRun();
    FormDataSource ds = formRun.dataSource(formDataSourceStr(ProdTableCreate, ProdTable));
    ProdTable prod = ds.cursor();

    // Clear ItemId only if SalesId changed
    if (prod.orig().ETGSalesId != prod.ETGSalesId)
    {
        prod.ETGItemId = '';
        ds.refresh();
    }

}
